INSERT INTO marketplace_skills (skill_id, name, display_name, description, category, domain, acuterium_thread, acuterium_thread_code, acuterium_shard, acuterium_layers, sovereignty_score, governance_level, author, source, source_url, license, version, status, tags, trigger_keywords, use_cases, skill_file, created_at, updated_at, registry_version, uuid) VALUES ('ACU-SKILL-1780', 'securing-azure-with-microsoft-defender', 'Securing Azure With Microsoft Defender', 'This skill instructs security practitioners on deploying Microsoft Defender for Cloud as a cloud-native application protection platform for Azure, multi-cloud, and hybrid environments. It covers enabling Defender plans for servers, containers, storage, and databases, configuring security recommendations, managing Secure Score, and integrating with the unified Defender portal for centralized threat management.
