INSERT INTO marketplace_skills (skill_id, name, display_name, description, category, domain, acuterium_thread, acuterium_thread_code, acuterium_shard, acuterium_layers, sovereignty_score, governance_level, author, source, source_url, license, version, status, tags, trigger_keywords, use_cases, skill_file, created_at, updated_at, registry_version, uuid) VALUES ('ACU-SKILL-1785', 'securing-kubernetes-on-cloud', 'Securing Kubernetes On Cloud', 'This skill covers hardening managed Kubernetes clusters on EKS, AKS, and GKE by implementing Pod Security Standards, network policies, workload identity, RBAC scoping, image admission controls, and runtime security monitoring. It addresses cloud-specific security features including IRSA for EKS, Workload Identity for GKE, and Managed Identities for AKS.
