INSERT INTO marketplace_skills (skill_id, name, display_name, description, category, domain, acuterium_thread, acuterium_thread_code, acuterium_shard, acuterium_layers, sovereignty_score, governance_level, author, source, source_url, license, version, status, tags, trigger_keywords, use_cases, skill_file, created_at, updated_at, registry_version, uuid) VALUES ('ACU-SKILL-4004', 'claude-sdk-tool-orchestration', 'Claude SDK Tool Orchestration', 'Orchestrates multi-tool workflows in Claude SDK agents using programmatic tool calling patterns that reduce token usage by up to 37% compared to prompt-based approaches. Supports parallel tool execution, tool result caching, and conditional tool invocation based on prior results. Includes the Tool Use Examples standard for universal tool demonstration.', 'tool-integration', 'infrastructure', 'T01 — COSM', 'T01', 'ADOCP', '["L5", "L6"]', 9, 'mandatory', 'Anthropic', 'anthropic/claude-code-sdk-python', 'https://github.com/anthropic/claude-code-sdk-python', 'Anthropic License', '0.0.14', 'published', '["anthropic", "claude", "tool-use", "programmatic", "orchestration", "tool-calling", "efficiency"]', '["claude tool use", "anthropic tools", "claude programmatic tools", "tool orchestration claude"]', '["Token-efficient multi-tool pipelines", "Automated tool-driven workflows with Claude"]', '', '2026-03-09T08:30:00Z', '2026-03-09T08:30:00Z', '7.0.0', 'f00f0d65-8431-4305-a8a3-36816e6b5cf0');
INSERT INTO marketplace_skills (skill_id, name, display_name, description, category, domain, acuterium_thread, acuterium_thread_code, acuterium_shard, acuterium_layers, sovereignty_score, governance_level, author, source, source_url, license, version, status, tags, trigger_keywords, use_cases, skill_file, created_at, updated_at, registry_version, uuid) VALUES ('ACU-SKILL-4005', 'claude-sdk-mcp-integration', 'Claude SDK MCP Integration', 'Connects Claude SDK agents to Model Context Protocol (MCP) servers to extend agent capabilities with external tools, resources, and prompts. Supports local stdio MCP servers and remote SSE-based servers with automatic tool discovery and schema validation. Enables Claude agents to use any MCP-compatible tool ecosystem including databases, APIs, and file systems.', 'mcp', 'infrastructure', 'T01 — COSM', 'T01', 'ADOCP', '["L5", "L6"]', 9, 'mandatory', 'Anthropic', 'anthropic/claude-code-sdk-python', 'https://github.com/anthropic/claude-code-sdk-python', 'Anthropic License', '0.0.14', 'published', '["anthropic", "claude", "mcp", "model-context-protocol", "mcp-server", "tool-discovery"]', '["claude mcp", "anthropic mcp", "claude model context protocol", "mcp claude integration"]', '["Extending Claude agents with MCP tool servers", "Claude agents with database access via MCP"]', '', '2026-03-09T08:30:00Z', '2026-03-09T08:30:00Z', '7.0.0', 'f5cbbddc-bbad-4832-82ba-f7a7a35ab3c9');
