INSERT INTO marketplace_skills (skill_id, name, display_name, description, category, domain, acuterium_thread, acuterium_thread_code, acuterium_shard, acuterium_layers, sovereignty_score, governance_level, author, source, source_url, license, version, status, tags, trigger_keywords, use_cases, skill_file, created_at, updated_at, registry_version, uuid) VALUES ('ACU-SKILL-4019', 'magentic-one-benchmark-optimization', 'Magentic-One Benchmark Optimization', 'Configures Magentic-One agent teams for optimal performance on GAIA, AssistantBench, and WebArena benchmarks by tuning agent compositions, model selections, and ledger update strategies. Provides recipes for heterogeneous model configurations pairing frontier models for orchestration with cost-efficient models for execution. Supports custom benchmark harness integration for domain-specific evaluation.', 'testing', 'cognitive', 'T04 — ACIW', 'T04', 'AcuTect-CODEX', '["L5", "L6", "L7", "L8"]', 10, 'mandatory', 'Microsoft', 'microsoft/autogen', 'https://github.com/microsoft/autogen/tree/main/python/packages/autogen-magentic-one', 'MIT', '0.4.0', 'published', '["magentic-one", "benchmark", "gaia", "webarena", "evaluation", "optimization", "tuning"]', '["magentic benchmark", "agent benchmark", "gaia benchmark", "webarena agent", "agent evaluation"]', '["Measuring and improving agent system quality", "Competitive benchmarking of multi-agent systems"]', '', '2026-03-09T08:30:00Z', '2026-03-09T08:30:00Z', '7.0.0', '9a4ec34c-c9c0-46e2-aa04-cf24ebcdb377');
INSERT INTO marketplace_skills (skill_id, name, display_name, description, category, domain, acuterium_thread, acuterium_thread_code, acuterium_shard, acuterium_layers, sovereignty_score, governance_level, author, source, source_url, license, version, status, tags, trigger_keywords, use_cases, skill_file, created_at, updated_at, registry_version, uuid) VALUES ('ACU-SKILL-4020', 'magentic-one-heterogeneous-models', 'Magentic-One Heterogeneous Model Configuration', 'Configures Magentic-One to use different LLMs for different agents in the team, assigning high-capability models to orchestration roles and cost-efficient models to execution roles. Supports mixing OpenAI, Azure OpenAI, Anthropic, Google, and open-source models within a single Magentic-One deployment. Enables cost-performance optimization through strategic model allocation.', 'ai-orchestration', 'cognitive', 'T01 — COSM', 'T01', 'Diaran-MOE', '["L5", "L6", "L7", "L8"]', 10, 'mandatory', 'Microsoft', 'microsoft/autogen', 'https://github.com/microsoft/autogen/tree/main/python/packages/autogen-magentic-one', 'MIT', '0.4.0', 'published', '["magentic-one", "heterogeneous", "multi-model", "model-mixing", "cost-optimization", "llm"]', '["heterogeneous models", "multi-model agents", "model mixing", "magentic model config", "cost efficient agents"]', '["Cost-optimized agent teams with mixed model tiers", "Enterprise deployments with model governance policies"]', '', '2026-03-09T08:30:00Z', '2026-03-09T08:30:00Z', '7.0.0', 'b266d67f-6efc-40ae-845e-35a70eeeb0ee');
