INSERT INTO marketplace_skills (skill_id, name, display_name, description, category, domain, acuterium_thread, acuterium_thread_code, acuterium_shard, acuterium_layers, sovereignty_score, governance_level, author, source, source_url, license, version, status, tags, trigger_keywords, use_cases, skill_file, created_at, updated_at, registry_version, uuid) VALUES ('ACU-SKILL-4068', 'a2a-protocol-agent-communication', 'A2A Protocol Agent-to-Agent Communication', 'Implements the Agent-to-Agent (A2A) protocol for standardized, interoperable communication between AI agents using JSON-RPC 2.0 over HTTP(S). Enables agents built on different frameworks (AutoGen, OpenAI Agents SDK, Google ADK, LangChain) to communicate through a common protocol. Supports synchronous request/response, server-sent events streaming, and asynchronous push notification patterns.', 'ai-orchestration', 'cognitive', 'T01 — COSM', 'T01', 'Diaran-MOE', '["L5", "L6", "L7", "L8"]', 10, 'mandatory', 'A2A Project / Google', 'a2aproject/A2A', 'https://github.com/a2aproject/A2A', 'Apache-2.0', '0.2.4', 'published', '["a2a", "agent-to-agent", "protocol", "json-rpc", "http", "interoperability", "communication"]', '["a2a protocol", "agent to agent", "a2a communication", "agent interoperability", "a2a json-rpc"]', '["Cross-framework agent interoperability", "Standardized agent-to-agent API communication"]', '', '2026-03-09T08:30:00Z', '2026-03-09T08:30:00Z', '7.0.0', '71cfd389-30fe-4264-adf4-952f088a6f07');
